input.command:
ADMIN_PASS=$(kubectl get secret admin-user-password -n mongodb -o jsonpath='{.data.password}' | base64 -d)

for pod in mongodb-replica-0 mongodb-replica-1 mongodb-replica-2; do
  echo "=== $pod ==="
  kubectl exec -n mongodb $pod -- mongosh --quiet \
    "mongodb://admin-user:${ADMIN_PASS}@localhost:27017/admin" \
    --eval '
      var cfg = db.adminCommand({getCmdLineOpts: 1});
      print("verbosity:", cfg.parsed.systemLog && cfg.parsed.systemLog.verbosity);
      print("slowOpThresholdMs:", cfg.parsed.operationProfiling && cfg.parsed.operationProfiling.slowOpThresholdMs);
      print("journalCompressor:", cfg.parsed.storage && cfg.parsed.storage.wiredTiger && cfg.parsed.storage.wiredTiger.engineConfig && cfg.parsed.storage.wiredTiger.engineConfig.journalCompressor);
    ' 2>&1
done
